import React, { useState } from "react";
import "./App.css";

function App() {
  const [esLogin, setEsLogin] = useState(true);
  const [rol, setRol] = useState("estudiante"); // 'estudiante' o 'empresa'

  const cambiarModo = () => setEsLogin(!esLogin);
  const cambiarRol = (nuevoRol) => setRol(nuevoRol);

  return (
    <div className="contenedor-autenticacion">
      <div className="encabezado-autenticacion">
        <h1>{esLogin ? "Bienvenido de nuevo" : "Crea tu cuenta"}</h1>
        <p>
          {esLogin
            ? "Accede a las mejores oportunidades universitarias"
            : `Regístrate como ${rol === "estudiante" ? "estudiante" : "empresa"} para comenzar`}
        </p>
      </div>

      <div className="selector-rol">
        <button
          className={`boton-rol ${rol === "estudiante" ? "activo" : ""}`}
          onClick={() => cambiarRol("estudiante")}
        >
          Estudiante
        </button>
        <button
          className={`boton-rol ${rol === "empresa" ? "activo" : ""}`}
          onClick={() => cambiarRol("empresa")}
        >
          Empresa
        </button>
      </div>

      <form
        className="formulario-autenticacion"
        onSubmit={(e) => e.preventDefault()}
      >
        {/* Solo correo y contraseña en ambos casos como se solicitó */}
        <div className="grupo-formulario">
          <label htmlFor="correo">Correo Electrónico</label>
          <input
            type="email"
            id="correo"
            className="campo-entrada"
            placeholder="ejemplo@universidad.edu"
            required
          />
        </div>

        <div className="grupo-formulario">
          <label htmlFor="contrasena">Contraseña</label>
          <input
            type="password"
            id="contrasena"
            className="campo-entrada"
            placeholder="••••••••"
            required
          />
        </div>

        {!esLogin && (
          <div className="grupo-formulario">
            <label htmlFor="confirmarContrasena">Confirmar Contraseña</label>
            <input
              type="password"
              id="confirmarContrasena"
              className="campo-entrada"
              placeholder="••••••••"
              required
            />
          </div>
        )}

        <button type="submit" className="boton-primario">
          {esLogin ? "Iniciar Sesión" : "Registrarse"}
        </button>
      </form>

      <div className="pie-autenticacion">
        <p>
          {esLogin ? "¿No tienes una cuenta?" : "¿Ya tienes una cuenta?"}{" "}
          <a
            href="#"
            onClick={(e) => {
              e.preventDefault();
              cambiarModo();
            }}
          >
            {esLogin ? "Regístrate aquí" : "Inicia sesión"}
          </a>
        </p>
      </div>
    </div>
  );
}

export default App;
